  1→// Match processing and tile merging logic
  2→
  3→import { SUPER_STREAK_THRESHOLD } from "./config.js";
  4→import {
  5→    createTile,
  6→    createJokerTile,
  7→    createWildTeleportTile,
  8→    createCursedTile,
  9→    isBlocked,
 10→    isBlockedWithLife,
 11→    isBlockedMovable,
 12→    isBlockedWithMergeCount,
 13→    isCursed,
 14→    getTileValue,
 15→    isTileStickyFreeSwapTile,
 16→    getDisplayValue,
 17→    isRectangularBlocked,
 18→} from "./tile-helpers.js";
 19→import {
 20→    showFormationTutorialDialog,
 21→    getPendingFormationTutorials,
 22→    highlightMergeTiles,
 23→    highlightBlockedTiles,
 24→    clearMergeHighlight,
 25→} from "./formation-tutorial.js";
 26→
 27→export async function processMatches(game, { animateMerges, animateUnblocking } = {}) {
 28→    const matchGroups = game.findMatches();
 29→
 30→    // Capture user swap flag before resetting (needed for processMerges callback)
 31→    const wasUserSwap = game.isUserSwap;
 32→    game.isUserSwap = false;
 33→
 34→    if (matchGroups.length === 0) {
 35→        // No matches found, allow interactions again
 36→        game.animating = false;
 37→        game.updateGoalDisplay(true);
 38→        return;
 39→    }
 40→
 41→    // Calculate score using display values (not internal values)
 42→    let totalScore = 0;
 43→    matchGroups.forEach((group) => {
 44→        const displayValue = getDisplayValue(group.value);
 45→        totalScore += displayValue * group.tiles.length;
 46→    });
 47→
 48→    // Update score
 49→    game.score += totalScore;
 50→    game.saveScore(); // Save score to localStorage
 51→
 52→    // Track score towards score goals
 53→    game.levelGoals.forEach((goal) => {
 54→        if (goal.goalType === "score") {
 55→            goal.current += totalScore;
 56→        }
 57→    });
 58→
 59→    // Check for pending formation tutorials (only on user swaps)
 60→    let showedTutorial = false;
 61→    if (wasUserSwap) {
 62→        const pendingTutorials = getPendingFormationTutorials(matchGroups, game.lastSwapPosition);
 63→
 64→        if (pendingTutorials.length > 0) {
 65→            showedTutorial = true;
 66→
 67→            // Highlight all tiles that will be merged and blocked tiles that will be removed
 68→            highlightMergeTiles(matchGroups);
 69→            highlightBlockedTiles(game, matchGroups);
 70→
 71→            // Wait 500ms so user can see the highlighted tiles before dialog opens
 72→            await new Promise((resolve) => setTimeout(resolve, 500));
 73→
 74→            // Show each tutorial dialog and wait for user to close it
 75→            for (const { formationType } of pendingTutorials) {
 76→                await showFormationTutorialDialog(formationType);
 77→            }
 78→
 79→            // Wait 800ms after dialog closes before continuing
 80→            await new Promise((resolve) => setTimeout(resolve, 800));
 81→
 82→            // Clear the highlight
 83→            clearMergeHighlight();
 84→        }
 85→    }
 86→
 87→    // Slow down animations after tutorial so user can see what happens
 88→    const speedMultiplier = showedTutorial ? 2 : 1;
 89→
 90→    // Check for blocked tiles adjacent to original match positions and unblock them
 91→    // Done after tutorial dialogs so blocked tiles are still visible during tutorial
 92→    const blockedTilesToRemove = unblockAdjacentTiles(game, matchGroups);
 93→
 94→    // Animate blocked tile removal
 95→    if (animateUnblocking) {
 96→        animateUnblocking(
 97→            game,
 98→            blockedTilesToRemove,
 99→            () => game.updateBlockedTileGoals(),
100→            (check) => game.updateGoalDisplay(check),
101→            speedMultiplier,
102→        );
103→    }
104→
105→    // Start merge animations, or process merges directly if no animation callback
106→    if (animateMerges) {
107→        animateMerges(
108→            game,
109→            matchGroups,
110→            (matchGroups) => processMerges(game, matchGroups, wasUserSwap),
111→            speedMultiplier,
112→        );
113→    } else {
114→        processMerges(game, matchGroups, wasUserSwap);
115→    }
116→}
117→
118→export function processMerges(game, matchGroups, wasUserSwap = false) {
119→    // Check for sticky free swap tiles BEFORE clearing the board
120→    matchGroups.forEach((group) => {
121→        group.hasStickyFreeSwap = group.tiles.some((tile) => {
122→            const boardTile = game.board[tile.row][tile.col];
123→            return isTileStickyFreeSwapTile(boardTile);
124→        });
125→    });
126→
127→    // Track cursed tiles that were successfully merged
128→    const mergedCursedTiles = [];
129→    matchGroups.forEach((group) => {
130→        group.tiles.forEach((tile) => {
131→            const boardTile = game.board[tile.row][tile.col];
132→            if (isCursed(boardTile)) {
133→                mergedCursedTiles.push({ row: tile.row, col: tile.col });
134→            }
135→        });
136→    });
137→
138→    // Update cursed goal progress for successfully merged cursed tiles
139→    mergedCursedTiles.forEach((pos) => {
140→        const tile = game.board[pos.row][pos.col];
141→        const value = getTileValue(tile);
142→        game.levelGoals.forEach((goal) => {
143→            if (goal.goalType === "cursed" && goal.tileValue === value) {
144→                goal.current++;
145→            }
146→        });
147→    });
148→
149→    // Track match statistics (only for user-initiated matches)
150→    if (wasUserSwap) {
151→        matchGroups.forEach((group) => {
152→            const tileCount = group.tiles.length;
153→            const direction = group.direction;
154→
155→            if (direction === "T-formation") {
156→                game.matchStats.tFormationCount++;
157→            } else if (direction === "L-formation") {
158→                game.matchStats.lFormationCount++;
159→            } else if (direction === "block_4_formation") {
160→                game.matchStats.blockFormationCount++;
161→            } else if (tileCount === 5) {
162→                game.matchStats.match5Count++;
163→            } else if (tileCount === 4) {
164→                game.matchStats.match4Count++;
165→            } else if (tileCount === 3) {
166→                game.matchStats.match3Count++;
167→            }
168→
169→            // Grant power-up for 5-tile formations (L, T, 5-line)
170→            if (
171→                direction === "L-formation" ||
172→                direction === "T-formation" ||
173→                direction === "line_5_horizontal" ||
174→                direction === "line_5_vertical"
175→            ) {
176→                game.grantFormationPowerUp(direction);
177→            }
178→        });
179→    }
180→
181→    // Clear all matched tiles first
182→    matchGroups.forEach((group) => {
183→        group.tiles.forEach((tile) => {
184→            game.board[tile.row][tile.col] = null;
185→        });
186→    });
187→
188→    // Create new merged tiles
189→    matchGroups.forEach((group) => {
190→        createMergedTiles(game, group, wasUserSwap);
191→    });
192→
193→    // Clear swap position after processing
194→    game.lastSwapPosition = null;
195→
196→    // Update goal display after creating new tiles (without checking completion)
197→    // Let the natural cascade completion in dropGems handle checkLevelComplete
198→    game.updateGoalDisplay(false);
199→
200→    // Re-render the board to show the merged tiles in their new state
201→    game.renderBoard();
202→
203→    // Check if we need to shift tile levels before continuing with cascade
204→    // This will animate the removal and then continue
205→    if (game.pendingTileLevelShift) {
206→        // Small delay to allow the render to complete
207→        setTimeout(() => {
208→            game.shiftTileLevels().then(() => {
209→                game.dropGems();
210→            });
211→        }, 50);
212→    } else {
213→        game.dropGems();
214→    }
215→}
216→
217→export function createMergedTiles(game, group, wasUserSwap = false) {
218→    const formationType = getFormationConfig(group.direction);
219→    let specialTileType = formationType ? game.specialTileConfig[formationType] : null;
220→
221→    // Calculate positions and value based on formation type
222→    const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
223→    const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
224→    const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(game, group.tiles, group);
225→    const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
226→
227→    // When Super Streak is active and the setting is enabled,
228→    // replace Wildcard (joker) rewards with Wildcard Teleport
229→    if (is5LineFormation && game.superStrikeWildcardTeleport && game.superStreak >= SUPER_STREAK_THRESHOLD) {
230→        specialTileType = "wild_teleport";
231→    }
232→
233→    const newValue = group.value + valueIncrement;
234→
235→    // Check if sticky free swap should transfer (detected before tiles were cleared)
236→    // If so, and this was NOT a user swap, transfer the sticky free swap to the merged tile
237→    const hasStickyFreeSwap = group.hasStickyFreeSwap || false;
238→    const transferStickyFreeSwap = hasStickyFreeSwap && !wasUserSwap;
239→
240→    // Track intermediate values for formations that skip a level (T, L, 5-line)
241→    // When tiles of value N merge into 1 tile of value N+2, conceptually there's an intermediate step:
242→    // - T/L formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
243→    // - 5-line formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
244→    // So we track 3 creations of the intermediate value (N+1)
245→    if (isTLFormation || is5LineFormation) {
246→        const intermediateValue = group.value + 1;
247→        trackGoalProgress(game, intermediateValue, 3);
248→    }
249→
250→    // Handle special tile types
251→    if (specialTileType === "joker" || specialTileType === "wild_teleport") {
252→        // Joker and wild_teleport are special - they create JOKER type tiles, not normal tiles with properties
253→        const createSpecialTile = specialTileType === "wild_teleport" ? createWildTeleportTile : createJokerTile;
254→
255→        if (positions.length > 1) {
256→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
257→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
258→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
259→
260→            game.board[specialPos.row][specialPos.col] = createSpecialTile();
261→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
262→            trackGoalProgress(game, newValue, 1);
263→        } else {
264→            game.board[positions[0].row][positions[0].col] = createSpecialTile();
265→        }
266→    } else if (specialTileType && specialTileType !== "none") {
267→        // All other special tile types use the same pattern
268→        // For directional free swaps, determine the direction
269→        let options = { transferStickyFreeSwap };
270→
271→        if (specialTileType === "freeswap_horizontal" || specialTileType === "freeswap_vertical") {
272→            // Determine swap direction from lastSwapPosition
273→            let isHorizontal = false;
274→            if (game.lastSwapPosition && game.lastSwapPosition.movedFrom) {
275→                const fromRow = game.lastSwapPosition.movedFrom.row;
276→                const toRow = game.lastSwapPosition.row;
277→
278→                // If rows are the same, it's a horizontal swap (columns differ)
279→                isHorizontal = fromRow === toRow;
280→            }
281→            options.isHorizontal = isHorizontal;
282→        }
283→
284→        if (positions.length > 1) {
285→            // For 2-position formations (4-tile line/block), create one special tile and one normal tile
286→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
287→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
288→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
289→
290→            game.board[specialPos.row][specialPos.col] = createTile(newValue, specialTileType, options);
291→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
292→            trackGoalProgress(game, newValue, 2);
293→        } else {
294→            // For 1-position formations (T, L, 5-line), create one special tile
295→            game.board[positions[0].row][positions[0].col] = createTile(newValue, specialTileType, options);
296→            trackGoalProgress(game, newValue, 1);
297→        }
298→    } else {
299→        // No special tile - create normal tiles at all positions
300→        // However, if transferStickyFreeSwap is true, the merged tiles should inherit the sticky free swap ability
301→        positions.forEach((pos) => {
302→            game.board[pos.row][pos.col] = createTile(newValue, null, { transferStickyFreeSwap });
303→        });
304→        trackGoalProgress(game, newValue, positions.length);
305→    }
306→
307→    // After creating merged tiles, check if any should become cursed
308→    positions.forEach((pos) => {
309→        checkAndCreateCursedTile(game, newValue, pos);
310→    });
311→
312→    // Check if we need to shift tile levels based on the newly created value
313→    // This just sets a flag and the highest value reached, doesn't execute the shift yet
314→    game.checkAndShiftTileLevels(newValue);
315→
316→    // Check if creating this value should grant a power-up reward
317→    game.checkAndGrantPowerUpReward(newValue);
318→}
319→
320→export function determineSpecialTilePosition(game, group, formationType) {
321→    // For 4-tile formations, determine which of the 2 middle positions should get the special tile
322→    // based on where the last swap was made
323→    if (!game.lastSwapPosition) {
324→        // If no swap info, default to first middle position
325→        if (formationType === "block_4") {
326→            return group.intersections[0];
327→        } else {
328→            const middlePositions = calculateMiddlePositions(game, group.tiles);
329→            return middlePositions[0];
330→        }
331→    }
332→
333→    const swapPos = game.lastSwapPosition;
334→
335→    if (formationType === "block_4") {
336→        // For block formation, choose the intersection closest to swap position
337→        // First check if the swapped tile is one of the intersections
338→        const matchingIntersection = group.intersections.find(
339→            (pos) => pos.row === swapPos.row && pos.col === swapPos.col,
340→        );
341→        if (matchingIntersection) {
342→            return matchingIntersection;
343→        }
344→
345→        // Otherwise, find which intersection is adjacent to the swapped position
346→        // The 2x2 block has positions at [r,c], [r,c+1], [r+1,c], [r+1,c+1]
347→        // Intersections are at [r,c+1] (top-right) and [r+1,c] (bottom-left)
348→        const adjacentIntersection = group.intersections.find((pos) => {
349→            const isAdjacent =
350→                (Math.abs(pos.row - swapPos.row) === 1 && pos.col === swapPos.col) ||
351→                (Math.abs(pos.col - swapPos.col) === 1 && pos.row === swapPos.row);
352→            return isAdjacent;
353→        });
354→
355→        if (adjacentIntersection) {
356→            return adjacentIntersection;
357→        }
358→
359→        // Fallback to distance-based (shouldn't reach here in normal gameplay)
360→        const distances = group.intersections.map((pos) => {
361→            const dist = Math.abs(pos.row - swapPos.row) + Math.abs(pos.col - swapPos.col);
362→            return { pos, dist };
363→        });
364→        distances.sort((a, b) => a.dist - b.dist);
365→        return distances[0].pos;
366→    } else if (formationType === "line_4") {
367→        // For line formation, choose the middle position that contains the swapped tile
368→        const middlePositions = calculateMiddlePositions(game, group.tiles);
369→
370→        // Check if swap position matches one of the middle positions
371→        const matchingPos = middlePositions.find((pos) => pos.row === swapPos.row && pos.col === swapPos.col);
372→
373→        if (matchingPos) {
374→            return matchingPos;
375→        }
376→
377→        // If swap position doesn't match, choose closest middle position
378→        const distances = middlePositions.map((pos) => {
379→            const dist = Math.abs(pos.row - swapPos.row) + Math.abs(pos.col - swapPos.col);
380→            return { pos, dist };
381→        });
382→        distances.sort((a, b) => a.dist - b.dist);
383→        return distances[0].pos;
384→    }
385→
386→    return null;
387→}
388→
389→function getFormationConfig(direction) {
390→    // Map direction to formation type for special tile config
391→    const formationMap = {
392→        "T-formation": "t_formation",
393→        "L-formation": "l_formation",
394→        block_4_formation: "block_4",
395→        line_4_horizontal: "line_4",
396→        line_4_vertical: "line_4",
397→        line_5_horizontal: "line_5",
398→        line_5_vertical: "line_5",
399→    };
400→
401→    return formationMap[direction] || null;
402→}
403→
404→export function calculateMiddlePositions(game, tiles, group = null) {
405→    const positions = [];
406→    const length = tiles.length;
407→
408→    // Special handling for T and L formations
409→    if (group && (group.direction === "T-formation" || group.direction === "L-formation")) {
410→        // For special formations, the "middle" position is the intersection
411→        positions.push(group.intersection);
412→        return positions;
413→    }
414→
415→    // Special handling for block formations
416→    if (group && group.direction === "block_4_formation") {
417→        // For block formations, the "middle" positions are the two intersections
418→        return group.intersections;
419→    }
420→
421→    // Special handling for 5-tile lines (should create 1 tile with 4x value)
422→    if (group && (group.direction === "line_5_horizontal" || group.direction === "line_5_vertical")) {
423→        // 5 tiles: middle position only (creates 1 tile with 4x value)
424→        positions.push(tiles[2]);
425→        return positions;
426→    }
427→
428→    // Regular match logic
429→    if (length === 3) {
430→        // 3 tiles: middle position (creates 1 tile with 2x value)
431→        positions.push(tiles[1]);
432→    } else if (length === 4) {
433→        // 4 tiles: two middle positions (creates 2 tiles with 2x value)
434→        positions.push(tiles[1]);
435→        positions.push(tiles[2]);
436→    } else if (length >= 5) {
437→        // 5+ tiles: single middle position (creates 1 tile with 4x value)
438→        positions.push(tiles[Math.floor(length / 2)]);
439→    }
440→
441→    return positions;
442→}
