444→function spawnDamageText(el, damage) {
445→    const rect = el.getBoundingClientRect();
446→    const dmgText = document.createElement("span");
447→    dmgText.className = "damage-text";
448→    dmgText.textContent = `-${damage}`;
449→    dmgText.style.left = `${rect.left + rect.width / 2}px`;
450→    dmgText.style.top = `${rect.top + rect.height * 0.3}px`;
451→    document.body.appendChild(dmgText);
452→    setTimeout(() => dmgText.remove(), 850);
453→}
454→
455→export function unblockAdjacentTiles(game, matchGroups) {
456→    const blockedTilesToRemove = [];
457→    const goalTilesToDamage = [];
458→    const cellsToDecrement = new Set(); // Track individual cells to decrement for merge-count blocks
459→
460→    matchGroups.forEach((group) => {
461→        // Track which blocked tiles have been hit by this match group
462→        const hitInThisGroup = new Set();
463→
464→        // Get where the new merged tile(s) will be created
465→        let targetPositions = [];
466→        if (group.direction === "T-formation" || group.direction === "L-formation") {
467→            targetPositions.push(group.intersection);
468→        } else if (group.direction === "block_4_formation") {
469→            targetPositions.push(...group.intersections);
470→        } else {
471→            const middlePositions = calculateMiddlePositions(game, group.tiles, group);
472→            targetPositions.push(...middlePositions);
473→        }
474→
475→        // Calculate the damage value from this match (the value of tiles being matched, not the merged result)
476→        const damageValue = getDisplayValue(group.value);
477→
478→        // Check each tile in the original match for adjacent blocked/goal tiles
479→        group.tiles.forEach((matchTile) => {
480→            const adjacentPositions = [
481→                { row: matchTile.row - 1, col: matchTile.col }, // Up
482→                { row: matchTile.row + 1, col: matchTile.col }, // Down
483→                { row: matchTile.row, col: matchTile.col - 1 }, // Left
484→                { row: matchTile.row, col: matchTile.col + 1 }, // Right
485→            ];
486→
487→            adjacentPositions.forEach((pos) => {
488→                // Check bounds
489→                if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
490→                    const tile = game.board[pos.row][pos.col];
491→
492→                    // Handle blocked tiles and blocked movable tiles (remove immediately)
493→
494→                    // Handle blocked tiles with life (apply damage)
495→                    if (isBlockedWithLife(tile)) {
496→                        // Use rectId for rectangular blocks, row_col for single cells
497→                        const key = isRectangularBlocked(tile) ? tile.rectId : `${pos.row}_${pos.col}`;
498→
499→                        // Skip if already hit by this match group
500→                        if (hitInThisGroup.has(key)) {
501→                            return;
502→                        }
503→                        hitInThisGroup.add(key);
504→
505→                        const existingEntry = goalTilesToDamage.find((t) => t.key === key);
506→
507→                        if (existingEntry) {
508→                            // Accumulate damage from different match groups
509→                            existingEntry.damage += damageValue;
510→                        } else {
511→                            // Find the closest target position for animation
512→                            let closestTarget = targetPositions[0];
513→                            let closestDistance =
514→                                Math.abs(pos.row - closestTarget.row) + Math.abs(pos.col - closestTarget.col);
515→
516→                            targetPositions.forEach((target) => {
517→                                const distance = Math.abs(pos.row - target.row) + Math.abs(pos.col - target.col);
518→                                if (distance < closestDistance) {
519→                                    closestDistance = distance;
520→                                    closestTarget = target;
521→                                }
522→                            });
523→
524→                            goalTilesToDamage.push({
525→                                key: key,
526→                                row: pos.row,
527→                                col: pos.col,
528→                                damage: damageValue,
529→                                targetPos: closestTarget,
530→                                tile: tile, // Store tile reference for rectangular blocks
531→                            });
532→                        }
533→                    }
534→                    // Handle blocked tiles with merge count (per-rectangle tracking)
535→                    else if (isBlockedWithMergeCount(tile)) {
536→                        // Skip if this RECTANGLE was already hit in this match group
537→                        // One match should only clear ONE cell from the entire block
538→                        if (hitInThisGroup.has(tile.rectId)) {
539→                            return;
540→                        }
541→                        hitInThisGroup.add(tile.rectId);
542→
543→                        // Find any cell in this rectangle that still needs clearing
544→                        // Also check cellsToDecrement to avoid picking a cell already claimed by another match group
545→                        let cellToClear = null;
546→                        for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
547→                            for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
548→                                const cellKey = `${r}_${c}`;
549→                                const rectCellKey = `${tile.rectId}_${cellKey}`;
550→                                // Only consider cells that have count > 0 AND haven't been claimed by another match
551→                                if (tile.cellMergeCounts[cellKey] > 0 && !cellsToDecrement.has(rectCellKey)) {
552→                                    cellToClear = { row: r, col: c, cellKey: cellKey };
553→                                    break;
554→                                }
555→                            }
556→                            if (cellToClear) break;
557→                        }
558→
559→                        // If we found a cell to clear, decrement it
560→                        if (cellToClear) {
561→                            const rectCellKey = `${tile.rectId}_${cellToClear.cellKey}`;
562→                            cellsToDecrement.add(rectCellKey);
563→
564→                            // Find the closest target position for animation
565→                            let closestTarget = targetPositions[0];
566→                            let closestDistance =
567→                                Math.abs(cellToClear.row - closestTarget.row) +
568→                                Math.abs(cellToClear.col - closestTarget.col);
569→
570→                            targetPositions.forEach((target) => {
571→                                const distance =
572→                                    Math.abs(cellToClear.row - target.row) + Math.abs(cellToClear.col - target.col);
573→                                if (distance < closestDistance) {
574→                                    closestDistance = distance;
575→                                    closestTarget = target;
576→                                }
577→                            });
578→
579→                            // Store for animation purposes
580→                            blockedTilesToRemove.push({
581→                                rectId: tile.rectId,
582→                                cellKey: cellToClear.cellKey,
583→                                row: cellToClear.row,
584→                                col: cellToClear.col,
585→                                targetPos: closestTarget,
586→                                tile: tile,
587→                                isMergeCount: true, // Flag for animation
588→                            });
589→                        }
590→                    } else if (isBlocked(tile) || isBlockedMovable(tile)) {
591→                        // Use rectId for deduplication
592→                        const key = isRectangularBlocked(tile) ? tile.rectId : `${pos.row}_${pos.col}`;
593→
594→                        // Skip if already hit by this match group
595→                        if (hitInThisGroup.has(key)) {
596→                            return;
597→                        }
598→                        hitInThisGroup.add(key);
599→
600→                        if (!blockedTilesToRemove.some((t) => t.key === key)) {
601→                            // Find the closest target position for animation
602→                            let closestTarget = targetPositions[0];
603→                            let closestDistance =
604→                                Math.abs(pos.row - closestTarget.row) + Math.abs(pos.col - closestTarget.col);
605→
606→                            targetPositions.forEach((target) => {
607→                                const distance = Math.abs(pos.row - target.row) + Math.abs(pos.col - target.col);
608→                                if (distance < closestDistance) {
609→                                    closestDistance = distance;
610→                                    closestTarget = target;
611→                                }
612→                            });
613→
614→                            blockedTilesToRemove.push({
615→                                key: key,
616→                                row: pos.row,
617→                                col: pos.col,
618→                                targetPos: closestTarget,
619→                                tile: tile, // Store tile reference
620→                            });
621→                        }
622→                    }
623→                }
624→            });
625→        });
626→    });
627→
628→    // Apply damage to blocked tiles with life
629→    goalTilesToDamage.forEach((entry) => {
630→        const tile = game.board[entry.row][entry.col];
631→        if (isBlockedWithLife(tile)) {
632→            const oldLife = tile.lifeValue;
633→            tile.lifeValue -= entry.damage;
634→            // If life goes below or equal to 0, mark for removal
635→            if (tile.lifeValue <= 0) {
636→                // Visual feedback: shake + damage text before death
637→                const elDying = isRectangularBlocked(tile)
638→                    ? document.querySelector(`[data-rect-id="${tile.rectId}"]`)
639→                    : document.querySelector(`[data-row="${entry.row}"][data-col="${entry.col}"]`);
640→                if (elDying) {
641→                    elDying.style.setProperty("--shake-intensity", "6px");
642→                    elDying.classList.add("blocked-dying");
643→                    spawnDamageText(elDying, entry.damage);
644→                }
645→                blockedTilesToRemove.push({
646→                    row: entry.row,
647→                    col: entry.col,
648→                    targetPos: entry.targetPos,
649→                });
650→            } else {
651→                // Visual feedback: shake + floating damage text
652→                const el = isRectangularBlocked(tile)
653→                    ? document.querySelector(`[data-rect-id="${tile.rectId}"]`)
654→                    : document.querySelector(`[data-row="${entry.row}"][data-col="${entry.col}"]`);
655→                if (el) {
656→                    const ratio = entry.damage / oldLife;
657→                    const intensity = Math.min(1 + ratio * 9, 10);
658→                    el.style.setProperty("--shake-intensity", `${intensity}px`);
659→                    el.classList.add("blocked-damaged");
660→                    el.dataset.life = tile.lifeValue;
661→
662→                    spawnDamageText(el, entry.damage);
663→
664→                    setTimeout(() => {
665→                        el.classList.remove("blocked-damaged");
666→                    }, 800);
667→                }
668→            }
669→        }
670→    });
671→
672→    // Decrement merge counts for affected cells
673→    const processedRects = new Set(); // Track which rectangles we've checked for full removal
674→    cellsToDecrement.forEach((rectCellKey) => {
675→        // Parse rectCellKey format: "rect_2_3_2_2_2_3" -> extract cell coordinates
676→        const parts = rectCellKey.split("_");
677→        const cellKey = `${parts[parts.length - 2]}_${parts[parts.length - 1]}`;
678→
679→        // Find the tile object (any cell in the rectangle will point to it)
680→        const [row, col] = cellKey.split("_").map(Number);
681→        const tile = game.board[row][col];
682→
683→        if (tile && isBlockedWithMergeCount(tile)) {
684→            // Decrement the cell's merge count
685→            tile.cellMergeCounts[cellKey]--;
686→
687→            // Check if ALL cells are cleared (all counts === 0) only once per rectangle
688→            if (!processedRects.has(tile.rectId)) {
689→                processedRects.add(tile.rectId);
690→
691→                const allCleared = Object.values(tile.cellMergeCounts).every((count) => count === 0);
692→
693→                if (allCleared) {
694→                    // Mark entire rectangular block for removal
695→                    blockedTilesToRemove.push({
696→                        rectId: tile.rectId,
697→                        row: tile.rectAnchor.row,
698→                        col: tile.rectAnchor.col,
699→                        tile: tile,
700→                        isFullRemoval: true,
701→                    });
702→                }
703→            }
704→        }
705→    });
706→
707→    return blockedTilesToRemove;
708→}
709→
710→function trackGoalProgress(game, newValue, count = 1) {
711→    // Update goal progress when tiles are created
712→    game.levelGoals.forEach((goal) => {
713→        if (goal.tileValue === newValue) {
714→            goal.created += count;
715→        }
716→    });
717→}
