719→export function checkAndCreateCursedTile(game, value, position) {
720→    // Check if this value has a cursed goal
721→    const cursedGoal = game.levelGoals.find((goal) => goal.goalType === "cursed" && goal.tileValue === value);
722→
723→    if (!cursedGoal) {
724→        return false; // No cursed goal for this value
725→    }
726→
727→    // Check if cursed goal is already complete
728→    if (cursedGoal.current >= cursedGoal.target) {
729→        return false; // Goal complete, no more cursed tiles
730→    }
731→
732→    // Special handling for frequency: 0
733→    // Always keep exactly one cursed tile on the board
734→    if (cursedGoal.frequency === 0) {
735→        // Check if we already created one this turn (to prevent multiple during cascades)
736→        if (game.cursedTileCreatedThisTurn[value]) {
737→            return false;
738→        }
739→
740→        // Scan the entire board to count cursed tiles of this value
741→        let cursedCount = 0;
742→        for (let row = 0; row < game.boardHeight; row++) {
743→            for (let col = 0; col < game.boardWidth; col++) {
744→                const tile = game.board[row][col];
745→                if (tile && isCursed(tile) && getTileValue(tile) === value) {
746→                    cursedCount++;
747→                }
748→            }
749→        }
750→
751→        // Only create if none exist
752→        if (cursedCount === 0) {
753→            const currentTile = game.board[position.row][position.col];
754→            if (currentTile && getTileValue(currentTile) === value) {
755→                const cursedTile = createCursedTile(value, cursedGoal.strength);
756→                game.board[position.row][position.col] = cursedTile;
757→                game.cursedTileCreatedThisTurn[value] = true; // Mark as created this turn
758→                return true;
759→            }
760→        }
761→        return false;
762→    }
763→
764→    // Normal frequency handling (frequency >= 1)
765→    // Track how many tiles of this value have been created
766→    if (!game.cursedTileCreatedCount[value]) {
767→        game.cursedTileCreatedCount[value] = 0;
768→    }
769→    game.cursedTileCreatedCount[value]++;
770→
771→    // Check if frequency is met (every Nth tile becomes cursed)
772→    if (game.cursedTileCreatedCount[value] % cursedGoal.frequency === 0) {
773→        // Convert the tile at this position to a cursed tile
774→        const currentTile = game.board[position.row][position.col];
775→        if (currentTile && getTileValue(currentTile) === value) {
776→            // Create cursed tile with full strength - decrement will happen at end of turn
777→            const cursedTile = createCursedTile(value, cursedGoal.strength);
778→            game.board[position.row][position.col] = cursedTile;
779→
780→            return true; // Cursed tile created
781→        }
782→    }
783→
784→    return false; // Not cursed
