            let leftCol = formationTile.col;
            let rightCol = formationTile.col;

            // Scan left
            while (leftCol > 0) {
                const row = game.board[formationTile.row];
                if (!row) break;
                const tile = row[leftCol - 1];
                if (!tile || (!isNormal(tile) && !isCursed(tile)) || !canMatch(tile, currentTile, game)) {
